const CLOSE_ICON = `<svg fill="currentColor" height="20" width="20" viewBox="0 0 12 16" role="presentation" aria-hidden="true">
	<path fill-rule="evenodd" fill="currentColor" d="M7.48 8l3.75 3.75-1.48 1.48L6 9.48l-3.75 3.75-1.48-1.48L4.52 8 .77 4.25l1.48-1.48L6 6.52l3.75-3.75 1.48 1.48L7.48 8z"></path>
</svg>`;

export class PWAPrompt extends IotaElement {
	#initialized = false;
	#name = this.use($text('No name provided'));
	#iconSrc = this.use($attr('src', '#'));
	#description = this.use($text('No description given.'));
	#relatedApplications = this.use($state([]));
	#screenshots = this.use($state([]));
	#categories = this.use($state([]));

	static #installDisabled = $disabled(true);
	static #resolvers = Promise.withResolvers();
	static #installPromptController = new AbortController();

	get html() {
		return html`
			<header id="header" part="header">
				<img ${this.#iconSrc} crossorigin="anonymous" referrerpolicy="no-referrer" part="icon" loading="lazy" alt="" />
				<span part="name">${this.#name}</span>
				<p part="description">${this.#description}</p>
				<button type="button" class="btn btn-primary" command="--install" part="install-btn" ${PWAPrompt.#installDisabled}>
					<slot name="install-icon">
						<svg class="current-color" height="20" width="20" viewBox="0 0 16 16" fill="currentColor" role="presentation" aria-hidden="true">
							<path d="M3 8h10v7.059c0 .492-.472.937-.996.937H4c-.539 0-1-.43-1-1z" overflow="visible"></path>
							<path d="M6.688 2.969a1 1 0 0 0-.657.375L3.22 6.812a1 1 0 0 0-.22.625v1a1 1 0 1 0 2 0v-.656l2.594-3.156a1 1 0 0 0-.907-1.656zm2.218 3a1 1 0 1 0-.031 2l2.156.375V8.5a1 1 0 1 0 2 0v-1a1 1 0 0 0-.812-1l-3-.5a1 1 0 0 0-.313-.031z" overflow="visible"></path>
						</svg>
					</slot>
					<span>Install</span>
				</button>
				<button type="button" class="btn btn-outline-danger" part="close-btn" command="hide-popover">
					${CLOSE_ICON}
				</button>
			</header>
			<p part="pwa-info">
				<slot name="pwa-info">This app can be installed on your PC or mobile device. This will allow this web app to look and behave like any other installed app. You will find it in your app lists and be able to pin it to your home screen, start menus or task bars. This installed web app will also be able to safely interact with other apps and your operating system. </slot>
			</p>
			<section class="flex row wrap stores" part="badges">
				<button type="button" class="install-btn" part="install-btn pwa-install" data-platform="webapp" command="--install" aria-label="Install PWA" ${PWAPrompt.#installDisabled}>
					<slot name="pwa-badge">${PWA_BADGE}</slot>
				</button>
				<a href="#" class="install-btn" part="install-btn apple-install" data-platform="itunes" hidden="" inert="">
					<slot name="apple-badge">${APP_STORE_BADGE}</slot>
				</a>
				<a href="#" class="install-btn" part="install-btn google-play-install" data-platform="play" hidden="" inert="">
					<slot name="google-play-badge">${GOOGLE_PLAY_BADGE}</slot>
				</a>
				<a href="#" class="install-btn" part="install-btn microsoft-install" data-platform="windows" hidden="" inert="">
					<slot name="microsoft-badge">${WINDOWS_BADGE}</slot>
				</a>
				<a href="#" class="install-btn" part="install-btn f-droid-install" data-platform="f-droid" hidden="" inert="">
					<slot name="f-droid-badge">${F_DROID_BADGE}</slot>
				</a>
				<a href="#" class="install-btn" part="install-btn amazon-install" data-platform="amazon" hidden="" inert="">
					<slot name="amazon-badge">${AMAZON_BADGE}</slot>
				</a>
			</section>
			<section id="screenshots"></section>
			<ul id="categories" part="categories" class="flex row no-wrap"></ul>
			<br />
			<button type="button" class="btn btn-danger" command="hide-popover" aria-label="Dismiss Install Prompt">
				${CLOSE_ICON}
			</button>
		`;
	}

	get styles() {
		return [
			btn, btnDanger, btnOutlineDanger, btnOutlinePrimary, btnPrimary,
			css`@layer components {
				:host {
					width: 90vw;
					max-height: 90dvh;
					overflow-y: auto;
					padding: 2em;
					border: none;
					border-radius: 12px;
				}

				#categories {
					display: flex;
					flex-direction: row;
					flex-wrap: no-wrap;
					overflow-x: auto;
					gap: 0.8rem;
				}

				.install-btn:not([hidden]) {
					apprearance: none;
					border: none;
					background: none;
					color: inherit;
					text-decoration: none;
					display: inline-block;
					padding: 0;
					margin: 0;
					cursor: pointer;

					&:disabled {
						filter: saturate(0);
						cursor: not-allowed;
					}
				}

				#screenshots {
					display: flex;
					flex-direction: row;
					gap: 1rem;
					overflow-x: auto;
					padding: 1rem 0;
					margin: 0;

					scroll-snap-type: x mandatory;
					scroll-behavior: smooth;
					-webkit-overflow-scrolling: touch;

					& > img {
						height: 350px;
						flex-shrink: 0;
						scroll-snap-align: center;
						border-radius: var(--aegis-border-radius, 8px);
						background-color: var(--aegis-surface-muted, #f8f9fa);
						box-shadow: 0 4px 6px rgba(0,0,0,0.1);

						width: auto;
						object-fit: contain; /* Prevents stretching/cropping */
						display: block;
					}
				}

				::part(name) {
					font-size: 1.8rem;
					font-weight: 800;
					font-family: system-ui;
				}

				#header {
					display: grid;
					grid-template-columns: 84px 1fr min-content;
					grid-template-rows: 34px 50px min-content;
					grid-template-areas:
						"icon name close"
						"icon desc desc"
						". install .";
					gap: 0.25rem 1rem;
					align-items: start;
					margin-bottom: 1.5rem;

					& > img[part="icon"] {
						grid-area: icon;
						width: 84px;
						aspect-ratio: 1;
						border-radius: 22.5%;
						object-fit: cover;
						box-shadow: 0 2px 6px rgba(0,0,0,0.1);
					}

					& > h1[part="name"] {
						grid-area: name;
						margin: 0;
						font-size: 1.4rem;
						line-height: 1.2;
						align-self: center;
					}

					& > p[part="description"] {
						grid-area: desc;
						margin: 0;
						font-size: 0.95rem;
						color: var(--aegis-text-muted, #6c757d);

						/* Forces the text to truncate with an ellipsis after 2 lines */
						display: -webkit-box;
						-webkit-line-clamp: 2;
						-webkit-box-orient: vertical;
						overflow: hidden;
					}

					& > button[command="hide-popover"] {
						grid-area: close;
						align-self: start;
						/* Assuming your btn-danger strips borders, this keeps it tight */
						padding: 0.25rem;
					}

					& > button[command="--install"] {
						grid-area: install;
						justify-self: stretch;
						padding-inline: 2rem;
						margin-top: 0.5rem;
						border-radius: 16px;
					}
				}

				[part="category"] {
					display: inline-block;
					background-color: var(--aegis-btn-primary, #0d6efd);
					color: var(--aegis-color-dark, #f8f9fa);
					border-radius: var(--aegis-btn-border-radius, 5px);
					padding: 0.6em 1.3em;
					list-style: none;
				}
			}`,
		];
	}

	get manifest() {
		return this.getAttribute('manifest') ?? this.ownerDocument.querySelector('link[rel="manifest"]')?.href ?? null;
	}

	update(type, context) {
		switch(type) {
			case 'connected':
				this.addEventListener('toggle', this, { once: true });
				this.#onConnect(context);
				break;

			case 'eventDispatched':
				this.#onEvent(context);
				break;
		}
	}

	#onConnect({ shadow }) {
		$watch(this.#relatedApplications, stores => {
			const storeMap = new Map(stores.map(store => [store.platform, store]));

			shadow.querySelectorAll('a[data-platform]').forEach(link => {
				if (storeMap.has(link.dataset.platform)) {
					link.hidden = false;
					link.inert = false;
					link.href = storeMap.get(link.dataset.platform).url;
				} else {
					link.hidden = true;
					link.inert = true;
				}
			});
		});

		$watch(this.#categories, categories => {
			const list = shadow.getElementById('categories');

			list.replaceChildren(...categories.map(category => {
				const li = document.createElement('li');
				li.textContent = category;
				li.part.add('category');
				return li;
			}));
		});

		$watch(this.#screenshots, screenshots => {
			shadow.getElementById('screenshots').replaceChildren(...screenshots.map(({ src, sizes }) => {
				const img = document.createElement('img');
				const [width, height] = sizes.split('x').map(s => parseInt(s));
				img.width = width;
				img.height = height;
				img.crossOrigin = 'anonymous';
				img.referrerPolicy = 'no-referrer';
				img.loading = 'lazy';
				img.src = src;
				img.alt = 'App Screenshot';
				img.part.add('screenshot');
				return img;
			}));
		});

		if (! this.hasAttribute('popover')) {
			this.popover = 'auto';
		}

		shadow.querySelectorAll('button[command]').forEach(btn => btn.commandForElement = this);
	}

	async #onEvent({ event, internals, signal }) {
		if (event.type === 'command') {
			switch(event.command) {
				case '--install':
					event.source.disabled = true;
					await this.#install(internals);
					break;
			}
		} else if (event.type === 'toggle' && ! this.#initialized) {
			this.#initialized = true;
			this.removeEventListener('toggle', this);
			await this.#loadManifest({ signal });
		}
	}

	async #loadManifest({ signal } = {}) {
		try {
			const manifest = this.manifest;

			if (typeof manifest === 'string') {
				const resp = await fetch(manifest, { signal });
				const { name, description, related_applications, icons, categories, screenshots } = await resp.json();

				if (typeof name === 'string') {
					this.#name.set(name);
				}

				if (typeof description === 'string') {
					this.#description.set(description);
				}

				if (Array.isArray(related_applications)) {
					this.#relatedApplications.set(related_applications);
				}

				if (Array.isArray(categories)) {
					this.#categories.set(categories);
				}

				if (Array.isArray(icons)) {
					this.#iconSrc.set(icons.find(({ type }) => type === 'image/svg+xml')?.src);
				}

				if (Array.isArray(screenshots)) {
					this.#screenshots.set(screenshots);
				}
			} else {
				throw new TypeError('No manifest for document.');
			}
		} catch(err) {
			this.requestUpdate('error', err);
		}
	}

	async #install(internals) {
		/**
		 * @type {BeforeInstallPromptEvent}
		 */
		const event = await PWAPrompt.#resolvers.promise;

		const result = await event.prompt();
		internals.states.add(`install-${result}`);
		PWAPrompt.#installDisabled.set(true);
	}

	/**
	 *
	 * @param {BeforeInstallPromptEvent} event
	 */
	static #beforeInstallPromptHandler(event) {
		event.preventDefault();
		PWAPrompt.#resolvers.resolve(event);
		PWAPrompt.#installDisabled.set(false);
		PWAPrompt.#installPromptController.abort();
	}

	static {
		this.register('pwa-prompt');

		if ('BeforeInstallPromptEvent' in globalThis) {
			globalThis.addEventListener('beforeinstallprompt', this.#beforeInstallPromptHandler, {
				once: true,
				signal: this.#installPromptController.signal,
			});
		} else {
			this.#resolvers.reject(new DOMException('`BeforeInstallPromptEvent` not supported.'));
		}
	}
}
